const express = require('express');
const mongoose = require('mongoose');
const mongoSanitize = require('express-mongo-sanitize');
const validator = require('validator');

const app = express();
app.use(express.json());

// Apply express-mongo-sanitize globally to strip $ and . from req.body
app.use(mongoSanitize({
  replaceWith: '_',  // Replace prohibited characters with underscore
  onSanitize: ({ req, key }) => {
    console.warn(`Sanitized key: ${key} in request from ${req.ip}`);
  }
}));

// Define strict Mongoose schema with validation
const UserSchema = new mongoose.Schema({
  username: {
    type: String,
    required: true,
    validate: {
      validator: (v) => validator.isAlphanumeric(v) && v.length >= 3 && v.length <= 20,
      message: 'Username must be 3-20 alphanumeric characters'
    }
  },
  email: {
    type: String,
    required: true,
    validate: {
      validator: (v) => validator.isEmail(v),
      message: 'Invalid email format'
    }
  },
  password: {
    type: String,
    required: true,
    minlength: 8
  },
  role: {
    type: String,
    enum: ['user', 'admin'],
    default: 'user'
  }
});

const User = mongoose.model('User', UserSchema);

// Secure login endpoint with type checking
app.post('/api/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Explicit type checking to prevent object injection
    if (typeof username !== 'string' || typeof password !== 'string') {
      return res.status(400).json({ error: 'Invalid input type' });
    }

    // Additional validation
    if (!validator.isAlphanumeric(username)) {
      return res.status(400).json({ error: 'Invalid username format' });
    }

    // Safe query using strict equality
    const user = await User.findOne({
      username: username,
      password: password  // In production, use bcrypt.compare()
    }).exec();

    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Generate session token
    res.json({ success: true, userId: user._id });

  } catch (error) {
    console.error('Login error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// NEVER allow direct user input in query operators
// BAD - Vulnerable:
// User.find({ age: { $gt: req.body.minAge } })

// GOOD - Validate and parse:
app.get('/api/users/search', async (req, res) => {
  try {
    const minAge = parseInt(req.query.minAge, 10);

    if (isNaN(minAge) || minAge < 0 || minAge > 150) {
      return res.status(400).json({ error: 'Invalid age parameter' });
    }

    const users = await User.find({
      age: { $gt: minAge }  // Safe because minAge is validated number
    }).select('username email age').exec();

    res.json(users);
  } catch (error) {
    res.status(500).json({ error: 'Search failed' });
  }
});

const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, QueryCommand } = require('@aws-sdk/lib-dynamodb');
const validator = require('validator');

const client = new DynamoDBClient({ region: 'us-east-1' });
const docClient = DynamoDBDocumentClient.from(client);

// Secure DynamoDB query using expression attribute values
async function getUserByEmail(email) {
  if (!validator.isEmail(email)) {
    throw new Error('Invalid email format');
  }

  const params = {
    TableName: 'Users',
    KeyConditionExpression: 'email = :emailValue',
    ExpressionAttributeValues: {
      ':emailValue': email  // Parameterized - prevents injection
    }
  };

  const result = await docClient.send(new QueryCommand(params));
  return result.Items;
}

// Secure filter with validation
async function searchUsers(minAge, role) {
  const age = parseInt(minAge, 10);
  if (isNaN(age) || age < 0 || age > 150) {
    throw new Error('Invalid age parameter');
  }

  const allowedRoles = ['user', 'admin', 'moderator'];
  if (!allowedRoles.includes(role)) {
    throw new Error('Invalid role parameter');
  }

  const params = {
    TableName: 'Users',
    FilterExpression: 'age >= :minAge AND #role = :roleValue',
    ExpressionAttributeNames: { '#role': 'role' },
    ExpressionAttributeValues: {
      ':minAge': age,
      ':roleValue': role
    }
  };

  const result = await docClient.send(new QueryCommand(params));
  return result.Items;
}

const express = require('express');
const app = express();

// Block dangerous operators middleware
function blockDangerousOperators(req, res, next) {
  const dangerousOps = ['$where', '$function', '$accumulator'];

  function containsDangerousOp(obj) {
    if (typeof obj !== 'object' || obj === null) return false;
    for (const key in obj) {
      if (dangerousOps.some(op => key.includes(op))) return true;
      if (typeof obj[key] === 'object' && containsDangerousOp(obj[key])) return true;
    }
    return false;
  }

  if (containsDangerousOp(req.body) || containsDangerousOp(req.query)) {
    console.warn();
    return res.status(400).json({ error: 'Invalid query operators' });
  }
  next();
}

app.use(blockDangerousOperators);

